@auto_docstring
class Qwen3MoeForCausalLM(Qwen3MoePreTrainedModel, GenerationMixin):
    _tied_weights_keys = {"lm_head.weight": "model.embed_tokens.weight"}
    _tp_plan = {"lm_head": "colwise_gather_output"}
    _pp_plan = {"lm_head": (["hidden_states"], ["logits"])}

    def __init__(self, config):
        super().__init__(config)
        self.model = Qwen3MoeModel(config)
        self.vocab_size = config.vocab_size
        self.lm_head = nn.Linear(config.hidden_size, config.vocab_size, bias=False)
        self.router_aux_loss_coef = config.router_aux_loss_coef
        self.num_experts = config.num_experts
        self.num_experts_per_tok = config.num_experts_per_tok

        # Initialize weights and apply final processing
        self.post_init()

    @can_return_tuple
    @auto_docstring
    def forward(
        self,
        input_ids: torch.LongTensor | None = None,
        attention_mask: torch.Tensor | None = None,
        position_ids: torch.LongTensor | None = None,
        past_key_values: Cache | None = None,
        inputs_embeds: torch.FloatTensor | None = None,
        labels: torch.LongTensor | None = None,
        use_cache: bool | None = None,
        output_router_logits: bool | None = None,
        cache_position: torch.LongTensor | None = None,
        logits_to_keep: int | torch.Tensor = 0,
        **kwargs: Unpack[TransformersKwargs],
    ) -> MoeCausalLMOutputWithLogProbs:
        output_router_logits = (
            output_router_logits if output_router_logits is not None else self.config.output_router_logits
        )

        outputs: MoeModelOutputWithPast = self.model(
            input_ids=input_ids,
            attention_mask=attention_mask,
            position_ids=position_ids,
            past_key_values=past_key_values,
            inputs_embeds=inputs_embeds,
            use_cache=use_cache,
            output_router_logits=output_router_logits,
            cache_position=cache_position,
            **kwargs,
        )

        hidden_states = outputs.last_hidden_state
        slice_indices = slice(-logits_to_keep, None) if isinstance(logits_to_keep, int) else logits_to_keep
        hidden_states = hidden_states[:, slice_indices, :]

        loss = None
        logits = None
        log_probs = None
        entropy = None
        if labels is not None:
            # Modification: OpSlot guard for cross-entropy loss.
            if veomni_causal_lm_loss.use_non_eager_impl:
                loss, logits, log_probs, entropy = veomni_causal_lm_loss(
                    logits=logits,
                    labels=labels,
                    vocab_size=self.config.vocab_size,
                    hidden_states=hidden_states,
                    weights=self.lm_head.weight,
                    **kwargs,
                )
            else:
                logits = self.lm_head(hidden_states)
                # Modification: VeOmni's patched `loss_function` (via LOSS_MAPPING)
                # returns (loss, logits, log_probs, entropy); unpack to match the
                # OpSlot branch above.
                loss, logits, log_probs, entropy = self.loss_function(
                    logits=logits, labels=labels, vocab_size=self.config.vocab_size, **kwargs
                )
        else:
            logits = self.lm_head(hidden_states)

        aux_loss = None
        if output_router_logits:
            # Modification: OpSlot guard for load-balancing loss.
            if veomni_load_balancing_loss.use_non_eager_impl:
                aux_loss = veomni_load_balancing_loss(
                    outputs.router_logits,
                    self.num_experts,
                    self.num_experts_per_tok,
                    attention_mask,
                )
            else:
                aux_loss = load_balancing_loss_func(
                    outputs.router_logits,
                    self.num_experts,
                    self.num_experts_per_tok,
                    attention_mask,
                )
            if labels is not None:
                loss += self.router_aux_loss_coef * aux_loss.to(loss.device)

        return MoeCausalLMOutputWithLogProbs(
            loss=loss,
            aux_loss=aux_loss,
            logits=logits,
            past_key_values=outputs.past_key_values,
            hidden_states=outputs.hidden_states,
            attentions=outputs.attentions,
            router_logits=outputs.router_logits,
            log_probs=log_probs,
            entropy=entropy,
        )

    def get_parallel_plan(self):
        from ..parallel_plan import get_parallel_plan as _get_parallel_plan

        return _get_parallel_plan()


